func dolog(message: String, level: UInt32) {
        if (isLoggable(level)) {
            unsafe {
                let cstr = LibC.mallocCString(message)
                HiLogPrint(type_, level, domain_, tag_, Hilog.STANDARD_FORMAT, cstr)
                LibC.free(cstr)
            }

