                cFormat = LibC.mallocCString(logContent).asResource()
            ) {
                HiLogPrint(DEFAULT_LOG_TYPE, LogLevel.Debug.getValue(), domain, cTag.value, STANDARD_FORMAT,
                    cFormat.value)
