        synchronized(dataLock) {
            let optData = store_.get(id)
            match (optData) {
                case Some(data) => getOrThrow(data as T, msg: "getOrCreate fail, data exist but type mismatch.")
                case _ =>
                    let data = creator(id)
                    store_.add(id, data)
                    data
            }

