/**
 * Developers need to implement this interface to provide data to LazyForEach component.
 * This interface defines the methods required for LazyForEach to access and monitor data.
 */
@!APILevel[
    since: "22",
    syscap: "SystemCapability.ArkUI.ArkUI.Full"
]
public interface IDataSource<T> {
    /**
     * Returns the count of all data items available in the data source.
     *
     * @returns { Int64 }

func totalCount(): Int64

    /**
     * Obtains the data item that matches the specified index.
     * Retrieves a specific data item from the data source by its index.
     *
     * @param { Int64 }

func getData(index: Int64): T

    /**
     * Adds a listener that will be notified when the data in the source changes.
     *
     * @param { DataChangeListener }

func registerDataChangeListener(listener: DataChangeListener): Unit

    /**
     * Removes a previously registered listener so it will no longer be notified of data changes.
     *
     * @param { DataChangeListener }

func unregisterDataChangeListener(listener: DataChangeListener): Unit
}

/**
 * Data change listener.
 */
@!APILevel[
    since: "22",
    syscap: "SystemCapability.ArkUI.ArkUI.Full"
]
public class DataChangeListener <: RemoteData {
    protected DataChangeListener(id: Int64) {
        super(id)
    }

func generateKey(idx: Int64): String {
        let data: T = getDataAndCache(idx)
        keyGeneratorFunc_(data, idx)
    }

func generateItem(idx: Int64): Unit {
        let data: T = getCachedData(idx)
        itemGeneratorFunc_(data, idx)
    }

func getTotalCount(): Int64 {
        return dataSource_.totalCount()
    }

func startMarkLazy(id: String): Unit {
        parentView_.markLazyForEachProcess(id)
    }

func endMarkLazy(): Unit {
        parentView_.resetLazyForEachProcess()
    }

func removeChildGroup(id: String): Unit {
        parentView_.removeChildGroupById(id)
    }

func onDestroyed(): Unit {
        for ((k, v) in cacheListener) {
            onRemoveDataChangeListener(v)
        }

func getDataAndCache(index: Int64): T {
        let data: T = dataSource_.getData(index)
        cacheData = (data, index)
        return data
    }

func getCachedData(index: Int64): T {
        let msg = "cached data index does not exist!"
        match (cacheData) {
            case None =>
                nativeLog(msg)
                throw BusinessException(100001, msg)
            case Some(realData) =>
                if (index != realData[1]) {
                    nativeLog(msg)
                    throw BusinessException(100001, msg)
                }

func dataChangeListenerRegister(listenerId: Int64) {
        let listener = if (cacheListener.contains(listenerId)) {
            cacheListener[listenerId]
        }

func dataChangeListenerUnregister(listenerId: Int64) {
        if (cacheListener.contains(listenerId)) {
            let listener = cacheListener[listenerId]
            onRemoveDataChangeListener(listener)
            cacheListener.remove(listenerId)
        }

func onRemoveDataChangeListener(listener: DataChangeListener): Unit {
        dataSource_.unregisterDataChangeListener(listener)
        listener.release()
    }

