func declareWatch<T>(propMember: ObservedProperty<T>, callBack: () -> Unit): Unit {
        match (propMember.getInner() as ObservedComplexAbstract) {
            case Some(value) =>
                watchedProps_inner__.add(value.getInfo(), callBack)
                let propsInfo = value.getPropsInfo()
