// callbackId -> callback
let id2Callback = HashMap<Int64, CallbackObject>()
// callback -> callbackId 
let callback2Id = HashMap<CallbackObject, Int64>()
let callbackIdGenerator = AtomicInt64(0)

protected func cjCallback2Argument<CJArgTypeA, CJArgTypeB>(callbackId: Int64, arg1: CJArgTypeA, arg2: CJArgTypeB) {
    let callback = id2Callback.get(callbackId)
    if (let Some(cb) <- callback) {
        (cb as Callback2Argument<CJArgTypeA, CJArgTypeB>).getOrThrow().invoke(None, arg1, arg2)
    }

func cjCallback1Argument<CJArgType>(callbackId: Int64, arg1: CJArgType) {
    let callback = id2Callback.get(callbackId)
    if (let Some(cb) <- callback) {
        (cb as Callback1Argument<CJArgType>).getOrThrow().invoke(None, arg1)
    }

func cjCallback0Argument(callbackId: Int64) {
    let callback = id2Callback.get(callbackId)
    if (let Some(cb) <- callback) {
        (cb as Callback0Argument).getOrThrow().invoke(None)
    }

func register(callback: CallbackObject): Int64 {
        var callbackId = callbackIdGenerator.fetchAdd(1)
        while (id2Callback.get(callbackId) != None) {
            callbackId = callbackIdGenerator.fetchAdd(1)
        }

func unregister(callback: CallbackObject): Int64 {
        let callbackId = callback2Id.get(callback)
        if (let Some(cbId) <- callbackId) {
            id2Callback.remove(cbId)
            callback2Id.remove(callback)
            return cbId
        }

